# OEIS sequence: A049077

from math import prod
from sympy import factorint
from sympy.ntheory.factor_ import digits
def A049077(n):
    if n&1 : return 1
    f, m = factorint(n), n>>1
    def s(n,p): return sum(digits(n,p)[1:])
    return n//prod(p**min(f[p],(s(m,p)+s(n-m,p)-s(n,p))//(p-1)) for p in f) # _Chai Wah Wu_, May 05 2026

